<?php namespace SmartChat; class Router { public function process_query($query) { $start_time = microtime(true); $mode = hmsc_get_option("mode", "hybrid"); $results = array(); if (in_array($mode, array("internal", "hybrid"))) { $results["internal"] = $this->search_internal($query); } if (in_array($mode, array("external", "hybrid"))) { $results["external"] = $this->search_external($query); } $answer = $this->combine_results($results, $query); $response_time = microtime(true) - $start_time; $this->log_query($query, $answer, $response_time); return array("answer" => $answer["text"], "sources" => $answer["sources"], "response_time" => round($response_time, 3)); } private function search_internal($query) { $limit = hmsc_get_option("internal_limit", 5); $args = array("post_type" => array("post", "page"), "post_status" => "publish", "posts_per_page" => $limit, "s" => $query); $posts = get_posts($args); $results = array(); foreach ($posts as $post) { $results[] = array("title" => $post->post_title, "url" => get_permalink($post->ID), "excerpt" => wp_trim_words($post->post_content, 20)); } return $results; } private function search_external($query) { $provider_name = hmsc_get_option("provider", "mock"); $provider_class = "SmartChat\\Providers\\Provider_" . ucfirst($provider_name); if (class_exists($provider_class)) { $provider = new $provider_class(); return $provider->search($query); } return array(); } private function combine_results($results, $query) { $mix_weight = hmsc_get_option("mix_weight", 70) / 100; $internal_weight = $mix_weight; $external_weight = 1 - $mix_weight; $combined_text = ""; $sources = array(); if (!empty($results["internal"])) { $internal_text = "Based on our website content:\n"; foreach ($results["internal"] as $result) { $internal_text .= "- " . $result["title"] . "\n"; $sources[] = array("type" => "internal", "title" => $result["title"], "url" => $result["url"]); } $combined_text .= $internal_text; } if (!empty($results["external"])) { $external_text = "\nAdditional information:\n"; foreach ($results["external"] as $result) { $external_text .= "- " . $result["title"] . "\n"; $sources[] = array("type" => "external", "title" => $result["title"], "url" => $result["url"]); } $combined_text .= $external_text; } if (empty($combined_text)) { $combined_text = "I could not find any relevant information for your question."; } return array("text" => $combined_text, "sources" => $sources); } private function log_query($query, $answer, $response_time) { if (!hmsc_get_option("enable_logs", false)) { return; } global $wpdb; $table_name = $wpdb->prefix . "hmsc_chat_logs"; $wpdb->insert($table_name, array("session_id" => session_id(), "user_ip" => $_SERVER["REMOTE_ADDR"] ?? "", "user_agent" => $_SERVER["HTTP_USER_AGENT"] ?? "", "question" => $query, "answer" => $answer["text"], "sources" => json_encode($answer["sources"]), "provider" => hmsc_get_option("provider", "mock"), "response_time" => $response_time)); } }
